# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import json
import logging
from google.cloud import storage, firestore, pubsub_v1
from google.cloud.exceptions import NotFound

def process_file_from_gcs(request):
    """Google Cloud Function to process files from Cloud Storage, write to Firestore, and publish to Pub/Sub"""
    
    # Initialize clients
    storage_client = storage.Client()
    db = firestore.Client()
    publisher = pubsub_v1.PublisherClient()
    
    # Get request data
    request_json = request.get_json(silent=True)
    
    if not request_json:
        return 'No JSON data provided', 400
    
    bucket_name = request_json.get('bucket')
    file_name = request_json.get('file')
    
    if not bucket_name or not file_name:
        return 'Bucket and file name required', 400
    
    try:
        # Download file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            return 'File not found', 404
            
        # Read file content
        content = blob.download_as_text()
        
        # Process content (example: parse JSON)
        try:
            data = json.loads(content)
        except json.JSONDecodeError:
            data = {"content": content}
        
        # Write to Firestore
        doc_ref = db.collection('processed_files').document(file_name)
        doc_ref.set({
            'filename': file_name,
            'bucket': bucket_name,
            'data': data,
            'processed_at': firestore.SERVER_TIMESTAMP
        })
        
        # Publish to Pub/Sub
        topic_path = publisher.topic_path('your-project-id', 'your-topic-name')
        
        # Prepare message
        message_data = {
            'filename': file_name,
            'bucket': bucket_name,
            'processed_data': data
        }
        
        message = json.dumps(message_data).encode('utf-8')
        
        # Publish message
        future = publisher.publish(topic_path, message)
        message_id = future.result()
        
        logging.info(f'Message published with ID: {message_id}')
        
        return f'Successfully processed {file_name}', 200
        
    except Exception as e:
        logging.error(f'Error processing file: {str(e)}')
        return f'Error: {str(e)}', 500